                    "code": "class GroupSignature:\n    \"\"\"群签名（Group Signature）实现\"\"\"\n    def __init__(self, group_name: str):\n        self.group_name = group_name\n        self.members: List[GroupMember] = []\n        self.group_public_keys: List[rsa.RSAPublicKey] = []\n        # 群管理员密钥（用于追踪）\n        self.admin_private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        self.admin_public_key = self.admin_private_key.public_key()\n        print(f\"[GroupSig] 群组 '{group_name}' 创建成功\")\n    \n    def add_member(self, member_id: str) -> GroupMember:\n        \"\"\"添加群成员并生成密钥对\"\"\"\n        private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        public_key = private_key.public_key()\n        member = GroupMember(member_id, private_key, public_key)\n        self.members.append(member)\n        self.group_public_keys.append(public_key)\n        print(f\"[GroupSig] 成员 '{member_id}' 加入群组\")\n        return member\n    \n    def sign(self, member: GroupMember, message: bytes) -> Tuple[bytes, bytes]:\n        \"\"\"群成员签名，返回签名和加密的身份信息\"\"\"\n        if member not in self.members:\n            raise ValueError(\"成员不在群组中\")\n        # 生成常规签名\n        signature = member.private_key.sign(\n            message,\n            padding.PSS(\n                mgf=padding.MGF1(hashes.SHA256()),\n                salt_length=padding.PSS.MAX_LENGTH\n            ),\n            hashes.SHA256()\n        )\n        # 加密签名者身份\n        identity_info = json.dumps({\n            'member_id': member.member_id,\n            'timestamp': str(hash(message))\n        }).encode()\n        encrypted_identity = self.admin_public_key.encrypt(\n            identity_info,\n            padding.OAEP(\n                mgf=padding.MGF1(algorithm=hashes.SHA256()),\n                algorithm=hashes.SHA256(),\n                label=None\n            )\n        )\n        print(f\"[GroupSig] 群成员生成匿名签名\")\n        return signature, encrypted_identity\n    \n    def verify(self, message: bytes, signature: bytes, encrypted_identity: bytes) -> bool:\n        \"\"\"验证群签名\"\"\"\n        for public_key in self.group_public_keys:\n            try:\n                public_key.verify(\n                    signature,\n                    message,\n                    padding.PSS(\n                        mgf=padding.MGF1(hashes.SHA256()),\n                        salt_length=padding.PSS.MAX_LENGTH\n                    ),\n                    hashes.SHA256()\n                )\n                print(f\"[GroupSig] 签名验证成功（来自群组 '{self.group_name}'）\")\n                return True\n            except:\n                continue\n        print(f\"[GroupSig] 签名验证失败\")\n        return False\n    \n    def trace(self, encrypted_identity: bytes) -> Optional[str]:\n        \"\"\"管理员追踪签名者\"\"\"\n        try:\n            identity_info = self.admin_private_key.decrypt(\n                encrypted_identity,\n                padding.OAEP(\n                    mgf=padding.MGF1(algorithm=hashes.SHA256()),\n                    algorithm=hashes.SHA256(),\n                    label=None\n                )\n            )\n            info = json.loads(identity_info)\n            member_id = info['member_id']\n            print(f\"[GroupSig] 管理员追踪：签名者是 '{member_id}'\")\n            return member_id\n        except:\n            print(f\"[GroupSig] 追踪失败\")\n            return None\n\n# 测试群签名\ndef demo_group_signature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"演示：群签名（Group Signature）\")\n    print(\"=\"*60)\n    group = GroupSignature(\"开发团队\")\n    alice = group.add_member(\"Alice\")\n    bob = group.add_member(\"Bob\")\n    carol = group.add_member(\"Carol\")\n    message = \"项目进度报告：Q1完成度90%\".encode()\n    signature, encrypted_id = group.sign(alice, message)\n    is_valid = group.verify(message, signature, encrypted_id)\n    signer_id = group.trace(encrypted_id)\n    return is_valid and signer_id == \"Alice\"\n\n# 执行测试\ndemo_group_signature()"
