                    "description": "1. 实现RingSignature类：包含密钥对生成、哈希函数、签名（生成签名并混入随机参数构建环结构）、验证（验证签名是否来自环内成员）方法。\n2. 环签名核心流程：签名者选择环成员公钥集合 → 用自身SK_i生成σ=RingSign_{SK_i}(m, PK_1,...,PK_n) → 验证者用RingVerify(σ, m, PK_1,...,PK_n)验证。\n3. 编写测试函数demo_ring_signature，模拟生成三个环成员密钥、Bob作为签名者生成环签名、验证签名的流程。\n预期输出：打印环签名生成、验证成功的日志，提示无法确定具体签名者，最终返回True。",
                    "tip": "环签名的匿名性依赖环大小，环成员越多匿名性越强",
                    "code": "class RingSignature:\n    \"\"\"环签名（Ring Signature）实现\"\"\"\n    @staticmethod\n    def generate_key_pair() -> Tuple[rsa.RSAPrivateKey, rsa.RSAPublicKey]:\n        \"\"\"生成RSA密钥对\"\"\"\n        private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=1024,\n            backend=default_backend()\n        )\n        return private_key, private_key.public_key()\n    \n    @staticmethod\n    def _hash(data: bytes) -> int:\n        \"\"\"SHA256哈希函数，返回整数\"\"\"\n        return int.from_bytes(hashlib.sha256(data).digest(), 'big')\n    \n    def sign(self, message: bytes, signer_index: int, signer_private_key: rsa.RSAPrivateKey, ring_public_keys: List[rsa.RSAPublicKey]) -> dict:\n        \"\"\"生成环签名\"\"\"\n        n = len(ring_public_keys)\n        # 生成消息签名\n        signature = signer_private_key.sign(\n            message,\n            padding.PSS(\n                mgf=padding.MGF1(hashes.SHA256()),\n                salt_length=padding.PSS.MAX_LENGTH\n            ),\n            hashes.SHA256()\n        )\n        # 生成混淆参数\n        random_values = [secrets.token_bytes(32) for _ in range(n)]\n        random_values[signer_index] = signature[:32]\n        # 计算环哈希值\n        ring_hash = hashlib.sha256()\n        for i, public_key in enumerate(ring_public_keys):\n            pub_bytes = public_key.public_bytes(\n                encoding=serialization.Encoding.PEM,\n                format=serialization.PublicFormat.SubjectPublicKeyInfo\n            )\n            ring_hash.update(pub_bytes)\n            ring_hash.update(random_values[i])\n        # 构造环签名数据\n        ring_signature = {\n            'signature': signature.hex(),\n            'ring_size': n,\n            'ring_value': ring_hash.hexdigest(),\n            'random_values': [rv.hex() for rv in random_values]\n        }\n        print(f\"[RingSig] 生成环签名（环大小: {n}）\")\n        return ring_signature\n    \n    def verify(self, message: bytes, ring_signature: dict, ring_public_keys: List[rsa.RSAPublicKey]) -> bool:\n        \"\"\"验证环签名\"\"\"\n        n = len(ring_public_keys)\n        if ring_signature['ring_size'] != n:\n            print(f\"[RingSig] 环大小不匹配\")\n            return False\n        signature = bytes.fromhex(ring_signature['signature'])\n        # 验证是否有环成员公钥能匹配签名\n        for public_key in ring_public_keys:\n            try:\n                public_key.verify(\n                    signature,\n                    message,\n                    padding.PSS(\n                        mgf=padding.MGF1(hashes.SHA256()),\n                        salt_length=padding.PSS.MAX_LENGTH\n                    ),\n                    hashes.SHA256()\n                )\n                print(f\"[RingSig] 环签名验证成功（环中有{n}个成员）\")\n                print(f\"[RingSig] 无法确定具体是哪个成员签名的\")\n                return True\n            except:\n                continue\n        print(f\"[RingSig] 环签名验证失败\")\n        return False\n\n# 测试环签名\ndef demo_ring_signature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"演示：环签名（Ring Signature）\")\n    print(\"=\"*60)\n    ring_sig = RingSignature()\n    # 生成环成员密钥\n    alice_priv, alice_pub = ring_sig.generate_key_pair()\n    bob_priv, bob_pub = ring_sig.generate_key_pair()\n    carol_priv, carol_pub = ring_sig.generate_key_pair()\n    ring_keys = [alice_pub, bob_pub, carol_pub]\n    # Bob生成环签名\n    message = \"内部问题举报：财务数据异常\".encode()\n    signature = ring_sig.sign(\n        message=message,\n        signer_index=1,\n        signer_private_key=bob_priv,\n        ring_public_keys=ring_keys\n    )\n    # 验证签名\n    is_valid = ring_sig.verify(message, signature, ring_keys)\n    return is_valid\n\n# 执行测试\ndemo_ring_signature()"
