                    "description": "1. 实现MultisignatureWallet类：包含初始化（设置阈值m和总签名者数n）、添加签名者（生成密钥对）、签名交易（收集达标数量的签名）、验证交易（验证签名有效性并统计达标数）方法。\n2. 多重签名核心流程：n个签名者各持SK_i → 每人生成σ_i=Sign_{SK_i}(m) → 合并为σ_multi=Combine(σ_1,...,σ_n) → 验证者用所有PK_i验证。\n3. 编写测试函数demo_multisignature，模拟创建2-of-3多签钱包、添加三位高管、创建交易、CEO和CFO联合签名、验证交易，以及测试单个签名失败的场景。\n预期输出：打印多签钱包创建、签名者添加、签名完成、验证成功的日志，单个签名尝试抛出异常，最终返回True。",
                    "tip": "多重签名的阈值设置需根据实际场景权衡安全性与易用性",
                    "code": "class MultisignatureWallet:\n    \"\"\"多重签名（Multisignature）钱包实现\"\"\"\n    def __init__(self, threshold: int, total: int):\n        \"\"\"初始化m-of-n多重签名钱包\"\"\"\n        if threshold > total or threshold < 1:\n            raise ValueError(\"无效的阈值\")\n        self.threshold = threshold\n        self.total = total\n        self.signers: List[Tuple[str, rsa.RSAPrivateKey, rsa.RSAPublicKey]] = []\n        print(f\"[MultiSig] 创建 {threshold}-of-{total} 多重签名钱包\")\n    \n    def add_signer(self, signer_id: str) -> rsa.RSAPrivateKey:\n        \"\"\"添加签名者\"\"\"\n        if len(self.signers) >= self.total:\n            raise ValueError(\"签名者数量已达上限\")\n        private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        public_key = private_key.public_key()\n        self.signers.append((signer_id, private_key, public_key))\n        print(f\"[MultiSig] 签名者 '{signer_id}' 已添加 ({len(self.signers)}/{self.total})\")\n        return private_key\n    \n    def sign_transaction(self, transaction: bytes, signer_indices: List[int]) -> List[bytes]:\n        \"\"\"签名交易，返回签名列表\"\"\"\n        if len(signer_indices) < self.threshold:\n            raise ValueError(f\"签名数不足，需要至少 {self.threshold} 个签名\")\n        signatures = []\n        for idx in signer_indices:\n            if idx >= len(self.signers):\n                raise ValueError(f\"签名者索引 {idx} 无效\")\n            signer_id, private_key, _ = self.signers[idx]\n            # 生成签名\n            signature = private_key.sign(\n                transaction,\n                padding.PSS(\n                    mgf=padding.MGF1(hashes.SHA256()),\n                    salt_length=padding.PSS.MAX_LENGTH\n                ),\n                hashes.SHA256()\n            )\n            signatures.append(signature)\n            print(f\"[MultiSig] '{signer_id}' 已签名\")\n        print(f\"[MultiSig] 交易签名完成 ({len(signatures)}/{self.threshold})\")\n        return signatures\n    \n    def verify_transaction(self, transaction: bytes, signatures: List[bytes], signer_indices: List[int]) -> bool:\n        \"\"\"验证多重签名交易\"\"\"\n        if len(signatures) < self.threshold:\n            print(f\"[MultiSig] 签名数不足\")\n            return False\n        valid_count = 0\n        for sig, idx in zip(signatures, signer_indices):\n            signer_id, _, public_key = self.signers[idx]\n            try:\n                public_key.verify(\n                    sig,\n                    transaction,\n                    padding.PSS(\n                        mgf=padding.MGF1(hashes.SHA256()),\n                        salt_length=padding.PSS.MAX_LENGTH\n                    ),\n                    hashes.SHA256()\n                )\n                valid_count += 1\n                print(f\"[MultiSig] '{signer_id}' 签名有效\")\n            except:\n                print(f\"[MultiSig] '{signer_id}' 签名无效\")\n        is_valid = valid_count >= self.threshold\n        if is_valid:\n            print(f\"[MultiSig] 交易验证成功 ({valid_count}/{self.threshold})\")\n        else:\n            print(f\"[MultiSig] 交易验证失败\")\n        return is_valid\n\n# 测试多重签名\ndef demo_multisignature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"演示：多重签名（Multisignature）\")\n    print(\"=\"*60)\n    # 创建2-of-3多签钱包\n    wallet = MultisignatureWallet(threshold=2, total=3)\n    # 添加签名者\n    wallet.add_signer(\"CEO\")\n    wallet.add_signer(\"CFO\")\n    wallet.add_signer(\"CTO\")\n    # 创建交易\n    transaction = \"转账：10 BTC 到地址 1A1zP1...\".encode()\n    # CEO和CFO签名\n    signatures = wallet.sign_transaction(transaction, signer_indices=[0, 1])\n    # 验证交易\n    is_valid = wallet.verify_transaction(transaction, signatures, [0, 1])\n    # 测试单个签名失败\n    print(\"\\n[步骤6] 尝试仅用一个签名（应该失败）\")\n    try:\n        single_sig = wallet.sign_transaction(transaction, signer_indices=[0])\n    except ValueError as e:\n        print(f\"[MultiSig] 错误：{e}\")\n    return is_valid\n\n# 执行测试\ndemo_multisignature()"
