                    "title": "比特承诺协议实现与测试",
                    "description": "1. 实现BitCommitment类：包含commit（承诺阶段）和reveal（揭示验证阶段）两个核心静态方法。承诺阶段采用哈希方案 $c=H(value||r)$，其中value为0/1比特，r为随机数；揭示阶段通过重新计算哈希值验证承诺有效性。\n2. 比特承诺核心特性：隐藏性（承诺阶段无法获取比特值）、绑定性（承诺后无法篡改比特值）。\n3. 编写测试函数demo_bit_commitment，模拟Alice承诺比特、Bob接收承诺、Alice揭示比特、验证有效性，以及尝试篡改比特的失败场景。\n预期输出：打印承诺创建、验证成功、篡改失败的日志信息，最终返回True。",
                    "code": "import hashlib\nimport secrets\nimport hmac\nfrom typing import List, Set, Tuple, Optional, Dict\nfrom dataclasses import dataclass\n\nclass BitCommitment:\n    \"\"\"比特承诺协议（Bit Commitment）实现\"\"\"\n    \n    @staticmethod\n    def commit(value: int, randomness: Optional[bytes] = None) -> Tuple[bytes, bytes]:\n        \"\"\"承诺一个比特值，返回（承诺值，随机数）\"\"\"\n        if value not in [0, 1]:\n            raise ValueError(\"值必须是0或1\")\n        \n        if randomness is None:\n            randomness = secrets.token_bytes(32)\n        \n        # 计算承诺: C = H(value || randomness)\n        commitment = hashlib.sha256(\n            str(value).encode() + randomness\n        ).digest()\n        \n        print(f\"[Commitment] 承诺已创建（值已隐藏）\")\n        return commitment, randomness\n    \n    @staticmethod\n    def reveal(commitment: bytes, value: int, randomness: bytes) -> bool:\n        \"\"\"揭示并验证承诺有效性\"\"\"\n        # 重新计算承诺\n        expected_commitment = hashlib.sha256(\n            str(value).encode() + randomness\n        ).digest()\n        \n        is_valid = hmac.compare_digest(commitment, expected_commitment)\n        \n        if is_valid:\n            print(f\"[Commitment] 承诺验证成功，揭示值: {value}\")\n        else:\n            print(f\"[Commitment] 承诺验证失败！\")\n        \n        return is_valid\n\n# 测试比特承诺\ndef demo_bit_commitment():\n    print(\"\\n\" + \"=\"*60)\n    print(\"演示：比特承诺协议\")\n    print(\"=\"*60)\n    \n    # Alice承诺一个比特\n    print(\"\\n[步骤1] Alice选择一个比特并承诺\")\n    alice_bit = 1\n    commitment, randomness = BitCommitment.commit(alice_bit)\n    print(f\"承诺值（哈希）: {commitment.hex()[:32]}...\")\n    \n    # Bob无法从承诺中得知比特值\n    print(\"\\n[步骤2] Bob看到承诺，但无法知道Alice的选择\")\n    \n    # Alice揭示\n    print(\"\\n[步骤3] Alice揭示她的比特\")\n    is_valid = BitCommitment.reveal(commitment, alice_bit, randomness)\n    \n    # 尝试作弊\n    print(\"\\n[步骤4] 如果Alice试图改变她的选择...\")\n    fake_bit = 0\n    is_valid_fake = BitCommitment.reveal(commitment, fake_bit, randomness)\n    \n    print(\"\\n[说明] 比特承诺的特性：\")\n    print(\"  1. 隐藏性：承诺阶段Bob不知道比特值\")\n    print(\"  2. 绑定性：Alice无法改变承诺的值\")\n    \n    return is_valid and not is_valid_fake\n\n# 执行测试\ndemo_bit_commitment()"
