                    "code": "class PedersenCommitment:\n    \"\"\"Pedersen承诺方案实现\"\"\"\n    \n    def __init__(self, p: Optional[int] = None):\n        \"\"\"初始化Pedersen承诺，默认使用固定大素数\"\"\"\n        # 简化版：使用一个标准大素数（256位）\n        if p is None:\n            self.p = \n        else:\n            self.p = p\n        \n        # 生成元\n        self.g = 2\n        self.h = 3\n        \n        print(f\"[Pedersen] 承诺方案初始化\")\n    \n    def commit(self, message: int) -> Tuple[int, int]:\n        \"\"\"创建Pedersen承诺，返回（承诺值，随机数）\"\"\"\n        # 生成随机数r（1<=r<p-1）\n        r = secrets.randbelow(self.p - 1)\n        \n        # 计算承诺：C = g^m * h^r mod p\n        commitment = (pow(self.g, message, self.p) * pow(self.h, r, self.p)) % self.p\n        \n        print(f\"[Pedersen] 承诺已创建\")\n        return commitment, r\n    \n    def verify(self, commitment: int, message: int, randomness: int) -> bool:\n        \"\"\"验证Pedersen承诺有效性\"\"\"\n        expected = (pow(self.g, message, self.p) * pow(self.h, randomness, self.p)) % self.p\n        \n        is_valid = (commitment == expected)\n        \n        if is_valid:\n            print(f\"[Pedersen] 承诺验证成功，消息: {message}\")\n        else:\n            print(f\"[Pedersen] 承诺验证失败\")\n        \n        return is_valid\n    \n    def add_commitments(self, c1: int, c2: int) -> int:\n        \"\"\"加法同态：C(m1 + m2) = C(m1) * C(m2) mod p\"\"\"\n        return (c1 * c2) % self.p\n\n# 测试Pedersen承诺\ndef demo_pedersen_commitment():\n    print(\"\\n\" + \"=\"*60)\n    print(\"演示：Pedersen承诺方案\")\n    print(\"=\"*60)\n    \n    pedersen = PedersenCommitment()\n    \n    print(\"\\n[步骤1] Alice承诺消息值42\")\n    message = 42\n    commitment, randomness = pedersen.commit(message)\n    print(f\"承诺值: {commitment}\")\n    \n    print(\"\\n[步骤2] 稍后Alice揭示消息\")\n    is_valid = pedersen.verify(commitment, message, randomness)\n    \n    print(\"\\n[步骤3] 演示加法同态性\")\n    m1, m2 = 10, 20\n    c1, r1 = pedersen.commit(m1)\n    c2, r2 = pedersen.commit(m2)\n    c_sum = pedersen.add_commitments(c1, c2)\n    print(f\"C(10) * C(20) = C(30)\")\n    print(f\"加法同态：可以在不知道消息的情况下计算承诺的和\")\n    \n    print(\"\\n[说明] Pedersen承诺的优势：\")\n    print(\"  1. 完美隐藏：计算能力无限也无法破解\")\n    print(\"  2. 加法同态：支持承诺运算\")\n    print(\"  3. 应用：零知识证明、隐私币\")\n    \n    return is_valid\n\n# 执行测试\ndemo_pedersen_commitment()"
