                    "tip": "简化版仅用于演示原理，实际应用需使用更安全的PSI协议（如基于OT的PSI）",
                    "code": "class PrivateSetIntersection:\n    \"\"\"隐私集合求交（PSI）协议实现（简化版）\"\"\"\n    \n    @staticmethod\n    def hash_set(items: Set[str], salt: bytes) -> Set[bytes]:\n        \"\"\"对集合元素加盐哈希，确保安全性\"\"\"\n        hashed = set()\n        for item in items:\n            h = hashlib.sha256(item.encode() + salt).digest()\n            hashed.add(h)\n        return hashed\n    \n    @classmethod\n    def compute_intersection_size(cls, alice_set: Set[str], \n                                  bob_set: Set[str]) -> int:\n        \"\"\"计算交集大小，不泄露非交集元素\"\"\"\n        # 生成共同盐值（实际应用中需安全协商）\n        salt = secrets.token_bytes(16)\n        \n        # 双方各自哈希自己的集合\n        alice_hashed = cls.hash_set(alice_set, salt)\n        bob_hashed = cls.hash_set(bob_set, salt)\n        \n        print(f\"[PSI] Alice集合大小: {len(alice_set)}\")\n        print(f\"[PSI] Bob集合大小: {len(bob_set)}\")\n        \n        # 计算哈希集合交集大小\n        intersection_size = len(alice_hashed & bob_hashed)\n        \n        print(f\"[PSI] 交集大小: {intersection_size}\")\n        print(f\"[PSI] 双方都不知道对方集合中的非交集元素\")\n        \n        return intersection_size\n    \n    @classmethod\n    def compute_intersection(cls, alice_set: Set[str], \n                            bob_set: Set[str]) -> Set[str]:\n        \"\"\"计算实际交集（演示用）\"\"\"\n        intersection = alice_set & bob_set\n        print(f\"[PSI] 计算出交集: {intersection}\")\n        return intersection\n\n# 测试PSI协议\ndef demo_psi():\n    print(\"\\n\" + \"=\"*60)\n    print(\"演示：隐私集合求交（PSI）\")\n    print(\"=\"*60)\n    \n    print(\"\\n场景：两家公司想知道有多少共同客户，但不想泄露自己的客户名单\")\n    \n    # 公司A的客户\n    company_a_customers = {\n        \"alice@example.com\",\n        \"bob@example.com\",\n        \"carol@example.com\",\n        \"dave@example.com\"\n    }\n    \n    # 公司B的客户\n    company_b_customers = {\n        \"bob@example.com\",\n        \"carol@example.com\",\n        \"eve@example.com\",\n        \"frank@example.com\"\n    }\n    \n    print(f\"\\n[公司A] 有{len(company_a_customers)}个客户（保密）\")\n    print(f\"[公司B] 有{len(company_b_customers)}个客户（保密）\")\n    \n    print(\"\\n[步骤1] 运行PSI协议\")\n    intersection_size = PrivateSetIntersection.compute_intersection_size(\n        company_a_customers,\n        company_b_customers\n    )\n    \n    print(f\"\\n[结果] 共同客户数：{intersection_size}\")\n    print(\"\\n[说明] PSI的优势：\")\n    print(\"  1. 双方只知道交集大小或交集\")\n    print(\"  2. 不泄露非交集元素\")\n    print(\"  3. 应用：广告转化、联系人发现、恶意软件检测\")\n    \n    # 验证结果正确性\n    actual_intersection = company_a_customers & company_b_customers\n    return len(actual_intersection) == intersection_size\n\n# 执行测试\ndemo_psi()"
